(function(){
  "use strict";const OA=window.OrbArena;
  class SettingsUI{
    constructor(app){this.app=app;this.defaults={quality:"high",visualPreset:"balanced",particleQuality:"medium",durationPreset:"standard",trails:true,glow:true,bloom:false,animatedBackground:true,arenaPreview:true,reducedMotion:false,reducedParticles:false,screenShake:true,freezeFrame:true,slowMotion:true,decals:true,distortion:false,shadows:true,lighting:true,statusEffects:true,adaptiveEffects:true,highContrast:false,largeText:false,reducedFlashes:false,colorblind:"none",uiScale:1};app.state.settings={...this.defaults,...app.state.settings};this.bind();this.apply();}
    bind(){const quality=document.querySelector("#graphics-quality"),visual=document.querySelector("#visual-preset"),particles=document.querySelector("#particle-quality");quality.onchange=e=>this.set("quality",e.target.value);visual.onchange=e=>this.applyPreset(e.target.value);particles.onchange=e=>this.set("particleQuality",e.target.value);document.querySelectorAll("[data-setting]").forEach(input=>{input.checked=this.app.state.settings[input.dataset.setting]??input.checked;input.onchange=()=>this.set(input.dataset.setting,input.checked);});document.querySelector("#colorblind-mode").onchange=e=>this.set("colorblind",e.target.value);document.querySelector("#ui-scale").oninput=e=>this.set("uiScale",+e.target.value);quality.value=this.app.state.settings.quality;visual.value=this.app.state.settings.visualPreset;particles.value=this.app.state.settings.particleQuality;document.querySelector("#colorblind-mode").value=this.app.state.settings.colorblind;document.querySelector("#ui-scale").value=this.app.state.settings.uiScale;}
    set(key,value){this.app.state.settings[key]=value;this.app.storage.saveSettings(this.app.state.settings);this.apply();}
    applyPreset(id){const preset=OA.VISUAL_PRESETS[id]||OA.VISUAL_PRESETS.balanced;Object.assign(this.app.state.settings,preset,{visualPreset:id});this.app.storage.saveSettings(this.app.state.settings);document.querySelector("#particle-quality").value=this.app.state.settings.particleQuality;document.querySelectorAll("[data-setting]").forEach(input=>{if(input.dataset.setting in this.app.state.settings)input.checked=this.app.state.settings[input.dataset.setting];});this.apply();}
    apply(){const s=this.app.state.settings,root=document.documentElement;root.style.setProperty("--ui-scale",s.uiScale);document.body.classList.toggle("reduced-motion",s.reducedMotion);document.body.classList.toggle("reduced-particles",s.reducedParticles);document.body.classList.toggle("high-contrast",s.highContrast);document.body.classList.toggle("large-text",s.largeText);document.body.classList.toggle("reduced-flashes",s.reducedFlashes);document.body.classList.toggle("no-glow",!s.glow);document.body.dataset.colorblind=s.colorblind;document.body.dataset.quality=s.quality;document.body.dataset.visualPreset=s.visualPreset;}
  }
  OA.SettingsUI=SettingsUI;
}());
